%MX101 := (WORD_TO_INT(%MW100) = 0);
%MX102 := (WORD_TO_INT(%MW100) = 1);
%MX103 := (WORD_TO_INT(%MW100) = 2);
%MX104 := (WORD_TO_INT(%MW100) = 3);
